changeSet.sql:
INSERT INTO country_i18n (country_id, lang, name) SELECT c.id, 'en', v.name FROM (VALUES ('CH','Switzerland'), ('KR','South Korea'), ('JP','Japan'), ('DE','Germany'), ('FR','France'), ('IT','Italy'), ('US','United States'), ('CN','China'), ('HK','Hong Kong'), ('AT','Austria'), ('GB','United Kingdom'), ('SE','Sweden') ) AS v(iso2, name) JOIN country c ON c.iso2 = v.iso2 ON CONFLICT (country_id, lang) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO country_i18n (country_id, lang, name) SELECT c.id, 'ru', v.name FROM (VALUES ('CH','Швейцария'), ('KR','Южная Корея'), ('JP','Япония'), ('DE','Германия'), ('FR','Франция'), ('IT','Италия'), ('US','США'), ('CN','Китай'), ('HK','Гонконг'), ('AT','Австрия'), ('GB','Великобритания'), ('SE','Швеция') ) AS v(iso2, name) JOIN country c ON c.iso2 = v.iso2 ON CONFLICT (country_id, lang) DO UPDATE SET name = EXCLUDED.name;
INSERT INTO country_i18n (country_id, lang, name) SELECT c.id, 'kz', v.name FROM (VALUES ('CH','Швейцария'), ('KR','Оңтүстік Корея'), ('JP','Жапония'), ('DE','Германия'), ('FR','Франция'), ('IT','Италия'), ('US','АҚШ'), ('CN','Қытай'), ('HK','Гонконг'), ('AT','Австрия'), ('GB','Ұлыбритания'), ('SE','Швеция') ) AS v(iso2, name) JOIN country c ON c.iso2 = v.iso2 ON CONFLICT (country_id, lang) DO UPDATE SET name = EXCLUDED.name;
